+    fn make_boundary(
+        id: &str,
+        kind: BoundaryKind,
+        src: PhaseRegion,
+        tgt: PhaseRegion,
+        sharpness: u64,
+    ) -> PhaseBoundary {
+        let mut b = PhaseBoundary {
+            boundary_id: id.to_string(),
+            kind,
+            coordinates: vec![coord("x", 0), coord("y", MILLIONTHS)],
+            source_region: src,
+            target_region: tgt,
