+    // Produce certificates.
+    let certificates: Vec<NoveltyCertificate> = scored
+        .iter()
+        .map(|score| {
+            let candidate = candidates
+                .iter()
+                .find(|c| c.candidate_id == score.candidate_id)
+                .expect("candidate must exist");
+            certify_candidate(candidate, score, config)
